        refBaseTablePartitionExprsOpt = Optional.empty();
        refBaseTablePartitionSlotsOpt = Optional.empty();
        refBaseTablePartitionColumnsOpt = Optional.empty();
        tableToBaseTableInfoCache.clear();
    }

