                props.put(TaskRun.FORCE, "true");
                return new MVPCTBasedRefreshProcessor(db, mv, mvContext, mvEntity, refreshMode);
            }
            default:
                return new MVPCTBasedRefreshProcessor(db, mv, mvContext, mvEntity, refreshMode);
        }
    }
